(function(){
function onReady(fn){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',fn);}else{fn();}}
onReady(function(){
  var card=document.querySelector('.vl-live-map-card');
  var mapNode=document.getElementById('vl-google-map');
  var overlay=document.getElementById('vl-map-route-overlay');
  var status=document.getElementById('vl-map-status');
  if(!card||!mapNode)return;
  card.dataset.routeMarkerCount='0';
  card.dataset.routeStatus='initializing';
  function label(name, fallback){return card.dataset[name]||fallback;}
  function setStatus(message, hidden){if(!status)return;status.textContent=message;status.hidden=!!hidden;}
  var key=(card.dataset.googleMapsApiKey||'').trim();
  var fallback={lat:Number(card.dataset.fallbackLat)||43.8828,lng:Number(card.dataset.fallbackLng)||-79.4403};
  var zoom=Number(card.dataset.mapZoom)||12;
  var minSites=Math.max(5,Number(card.dataset.routeMin)||5);
  var maxSites=Math.max(minSites,Math.min(15,Number(card.dataset.routeMax)||15));
  var routeRadiusKm=Number(card.dataset.routeRadiusKm)||4.5;
  var apiMap=null;
  var routePolylines=[];
  var siteMarkers=[];
  var routeBuildId=0;
  var apiAuthFailed=false;
  function randomSeed(){return Math.floor(Date.now()/86400000)+Math.floor(Math.random()*100000);}
  function rand(seed){var x=Math.sin(seed)*10000;return x-Math.floor(x);}
  function asLiteral(location){
    if(!location)return null;
    if(typeof location.lat==='function')return {lat:location.lat(),lng:location.lng()};
    return {lat:Number(location.lat),lng:Number(location.lng)};
  }
  function destinationPoint(center,distanceKm,angle){
    var dLat=(distanceKm/111)*Math.cos(angle);
    var dLng=(distanceKm/(111*Math.max(.2,Math.cos(center.lat*Math.PI/180))))*Math.sin(angle);
    return {lat:center.lat+dLat,lng:center.lng+dLng};
  }
  function candidateSites(center,countOverride,attempt){
    var seed=randomSeed()+attempt*1009;
    var count=countOverride||minSites+Math.floor(rand(seed+1)*(maxSites-minSites+1));
    var points=[];
    for(var i=0;i<count;i++){
      var angle=(Math.PI*2*i/count)+(rand(seed+i+2)-.5)*.5;
      var distance=routeRadiusKm*(.3+rand(seed+i+20)*.55)*(attempt>0?.75:1);
      points.push(destinationPoint(center,distance,angle));
    }
    points.sort(function(a,b){return Math.atan2(a.lat-center.lat,a.lng-center.lng)-Math.atan2(b.lat-center.lat,b.lng-center.lng);});
    return points;
  }
  function routePoints(center,sites){return [center].concat(sites||[]);}
  function clearRoute(){
    card.dataset.routeMarkerCount='0';
    routePolylines.forEach(function(polyline){polyline.setMap(null);});
    routePolylines=[];
    siteMarkers.forEach(function(marker){marker.setMap(null);});
    siteMarkers=[];
  }
  function addMarker(position,labelText,title){
    if(!apiMap||!window.google||!google.maps||!position)return;
    siteMarkers.push(new google.maps.Marker({position:position,map:apiMap,label:labelText,title:title}));
  }
  function drawOverlayMarkers(points){
    if(!overlay)return;
    overlay.innerHTML='';
    points.forEach(function(point,i){
      var dot=document.createElement('span');
      dot.className='vl-map-site-dot';
      dot.dataset.index=i===0?'C':String(i);
      dot.style.left=(50+Math.cos((Math.PI*2*i/points.length)-Math.PI/2)*(i===0?0:34))+'%';
      dot.style.top=(50+Math.sin((Math.PI*2*i/points.length)-Math.PI/2)*(i===0?0:34))+'%';
      overlay.appendChild(dot);
    });
  }
  function drawEmbedRoute(center, title, withMarkers){
    var points=routePoints(center,candidateSites(center,minSites,0));
    mapNode.innerHTML='';
    var frame=document.createElement('iframe');
    frame.title=title;
    frame.loading='eager';
    frame.referrerPolicy='no-referrer-when-downgrade';
    frame.src='https://www.google.com/maps?q='+encodeURIComponent(center.lat+','+center.lng)+'&z='+encodeURIComponent(zoom)+'&output=embed';
    mapNode.appendChild(frame);
    if(withMarkers){drawOverlayMarkers(points);}else if(overlay){overlay.innerHTML='';}
    setStatus('',true);
  }
  function placeMarkersFromRoute(route){
    var legs=route&&route.legs?route.legs:[];
    if(!legs.length)return;
    addMarker(asLiteral(legs[0].startLocation),'C','Current location');
    legs.forEach(function(leg,i){addMarker(asLiteral(leg.endLocation),String(i+1),'Service site '+(i+1));});
    card.dataset.routeMarkerCount=String(legs.length+1);
  }
  function fitRoute(route){
    if(!apiMap||!route||!route.path||!route.path.length)return;
    var bounds=new google.maps.LatLngBounds();
    route.path.forEach(function(point){bounds.extend(asLiteral(point));});
    apiMap.fitBounds(bounds,44);
  }
  function computeRoute(Route,center,sites){
    var points=routePoints(center,sites);
    var origin=points[0];
    var destination=points[points.length-1];
    var mids=points.slice(1,-1);
    return Route.computeRoutes({
      origin:{lat:origin.lat,lng:origin.lng},
      destination:{lat:destination.lat,lng:destination.lng},
      intermediates:mids.map(function(p){return {location:{lat:p.lat,lng:p.lng},vehicleStopover:true};}),
      travelMode:'DRIVING',
      fields:['path','legs']
    });
  }
  function requestDrivingRoute(center,attempt,buildId){
    if(!apiMap||apiAuthFailed||buildId!==routeBuildId)return;
    var count=Math.max(minSites,Math.floor(minSites+rand(randomSeed()+attempt+1)*(maxSites-minSites+1)));
    var sites=candidateSites(center,count,attempt);
    setStatus(attempt?'Finding alternate reachable service sites...':'Finding reachable service sites...',false);
    google.maps.importLibrary('routes').then(function(routesLibrary){
      if(buildId!==routeBuildId)return null;
      return computeRoute(routesLibrary.Route,center,sites);
    }).then(function(response){
      if(!response||buildId!==routeBuildId)return;
      var route=response.routes&&response.routes[0];
      var legs=route&&route.legs?route.legs:[];
      if(route&&legs.length>=minSites){
        clearRoute();
        routePolylines=route.createPolylines({polylineOptions:{strokeColor:'#176bff',strokeOpacity:.95,strokeWeight:6}});
        routePolylines.forEach(function(polyline){polyline.setMap(apiMap);});
        placeMarkersFromRoute(route);
        fitRoute(route);
        card.dataset.routeStatus='ready';
        setStatus('',true);
      }else if(attempt<3){
        requestDrivingRoute(center,attempt+1,buildId);
      }else{
        clearRoute();
        addMarker(center,'C','Current location');
        card.dataset.routeStatus='error';
        setStatus('Driving route is unavailable for these reachable service sites.',false);
      }
    }).catch(function(){
      if(buildId!==routeBuildId)return;
      if(attempt<3){requestDrivingRoute(center,attempt+1,buildId);return;}
      clearRoute();
      addMarker(center,'C','Current location');
      setStatus('Driving route is unavailable for these reachable service sites.',false);
    });
  }
  function buildDrivingRoute(center){
    if(apiAuthFailed||!apiMap||!window.google||!google.maps)return;
    routeBuildId++;
    if(overlay)overlay.innerHTML='';
    clearRoute();
    window.setTimeout(function(){requestDrivingRoute(center,0,routeBuildId);},250);
  }
  function initApiMap(center, title){
    if(apiAuthFailed||!window.google||!google.maps){return;}
    if(overlay)overlay.innerHTML='';
    clearRoute();
    apiMap=new google.maps.Map(mapNode,{center:center,zoom:zoom,mapTypeControl:false,streetViewControl:false,fullscreenControl:true});
    setStatus('',true);
    buildDrivingRoute(center);
  }
  function geolocateThenUpdate(){
    if(!navigator.geolocation)return;
    navigator.geolocation.getCurrentPosition(function(pos){
      var current={lat:pos.coords.latitude,lng:pos.coords.longitude};
      if(apiAuthFailed){
        drawEmbedRoute(current,label('currentLabel','Current browser location'),true);
        setStatus('Google Maps API key is not authorized for this page.',false);
        return;
      }
      drawEmbedRoute(current,label('currentLabel','Current browser location'),false);
      if(apiMap){initApiMap(current,label('currentLabel','Current browser location'));}
    },function(){}, {enableHighAccuracy:false,timeout:6000,maximumAge:300000});
  }
  drawEmbedRoute(fallback,label('fallbackLabel','Richmond Hill, Ontario, Canada'),!key);
  if(!key){setStatus(label('keyMissingLabel','Add a Google Maps API key in CMS to build a driving route.'),false);return;}
  window.__vlInitGoogleMap=function(){if(apiAuthFailed)return;initApiMap(fallback,label('fallbackLabel','Richmond Hill, Ontario, Canada'));geolocateThenUpdate();};
  if(window.google&&google.maps){window.__vlInitGoogleMap();return;}
  window.gm_authFailure=function(){apiAuthFailed=true;drawEmbedRoute(fallback,label('fallbackLabel','Richmond Hill, Ontario, Canada'),true);setStatus('Google Maps API key is not authorized for this page.',false);};
  var script=document.createElement('script');
  script.src='https://maps.googleapis.com/maps/api/js?key='+encodeURIComponent(key)+'&callback=__vlInitGoogleMap&loading=async';
  script.async=true;
  script.defer=true;
  script.onerror=function(){drawEmbedRoute(fallback,label('fallbackLabel','Richmond Hill, Ontario, Canada'),true);};
  document.head.appendChild(script);
});
})();
